void bubbleSort(List<int> lista) {
  for (var i = 0; i < lista.length - 1; i++) {
    for (var j = 0; j < lista.length - 1 - i; j++) {
      if (lista[j] > lista[j + 1]) {
        var t = lista[j];
        lista[j] = lista[j + 1];
        lista[j + 1] = t;
      }
    }
  }
}

